Freeze 功能 （openzeppelin-contracts v3.2.0之后）也叫做 pause 或者 close，具体就是停止 Token 相关的 transfer（转账）功能
// ERC 20pragma solidity ^0.5.0;import &#x27;openzeppelin-solidity/contracts/token/ERC20/ERC20.sol&#x27;;import &#x27;openzeppelin-solidity/contracts/token/ERC20/ERC20Detailed.sol&#x27;;import &#x27;openzeppelin-solidity/contracts/ownership/Ownable.sol&#x27;;contract MyERC20 is ERC20, ERC20Detailed, Ownable &#123;    bool public closed = false;    event Close();    event Open();    constructor(uint256 initialSupply) ERC20Detailed(&quot;MyToken&quot;, &quot;MT&quot;, 18) public &#123;        _mint(msg.sender, initialSupply);    &#125;    // ------------------------------------------------------------------------    // Don&#x27;t accept ETH    // ------------------------------------------------------------------------    function() external payable &#123;        revert(&quot;Don&#x27;t accept ETH&quot;);    &#125;    function transfer(address _to, uint _value) whenOpen public returns (bool) &#123;        return super.transfer(_to, _value);    &#125;    function transferFrom(address _from, address _to, uint _value) whenOpen public returns (bool) &#123;        return super.transferFrom(_from, _to, _value);    &#125;    function close() onlyOwner whenOpen public &#123;        closed = true;        emit Close();    &#125;    function open() onlyOwner whenClosed public &#123;        closed = false;        emit Open();    &#125;    modifier whenOpen() &#123;        require(!closed);        _;    &#125;    modifier whenClosed() &#123;        require(closed);        _;    &#125;&#125;

