MultiSigWallet 多方签名gnosis 的 multisignature 功能最为完善。已经有多个生产项目采用此工具。目前此工具合约的 solidity 版本为0.4.15，项目语言版本交旧，但没有发生过安全问题。
首先 ERC20 合约的初始化总金额地址需要给到 MultiSigWallet 的合约地址，由 MultiSigWallet 合约完成多方签名确认后，ERC20 代币从 MultiSigWallet 合约的地址发送到接收人的账户地址。
// ERC 20pragma solidity ^0.5.0;import &#x27;openzeppelin-solidity/contracts/token/ERC20/ERC20.sol&#x27;;import &#x27;openzeppelin-solidity/contracts/token/ERC20/ERC20Detailed.sol&#x27;;import &#x27;openzeppelin-solidity/contracts/ownership/Ownable.sol&#x27;;contract MyERC20 is ERC20, ERC20Detailed, Ownable &#123;    bool public closed = false;    event Close();    event Open();    constructor(uint256 initialSupply) ERC20Detailed(&quot;MyToken&quot;, &quot;MT&quot;, 18) public &#123;        _mint(msg.sender, initialSupply);    &#125;    // ------------------------------------------------------------------------    // Do accept ETH, deposit token in contract address    // ------------------------------------------------------------------------    function() external payable &#123;&#125;    function transfer(address _to, uint _value) whenOpen public returns (bool) &#123;        return super.transfer(_to, _value);    &#125;    function transferFrom(address _from, address _to, uint _value) whenOpen public returns (bool) &#123;        return super.transferFrom(_from, _to, _value);    &#125;    function close() onlyOwner whenOpen public &#123;        closed = true;        emit Close();    &#125;    function open() onlyOwner whenClosed public &#123;        closed = false;        emit Open();    &#125;    modifier whenOpen() &#123;        require(!closed);        _;    &#125;    modifier whenClosed() &#123;        require(closed);        _;    &#125;&#125;



