// CreateAccount 创建账户接口 func (accSt *AccountState) CreateAccount(addr common.Address) &#123;	if accSt.getAccountObject(addr) != nil &#123;		return	&#125;	obj := newAccountObject(addr, accountData&#123;&#125;)	accSt.setAccountObject(obj)&#125;// SubBalance 减去某个账户的余额func (accSt *AccountState) SubBalance(addr common.Address, amount *big.Int) &#123;	stateObject := accSt.getOrsetAccountObject(addr)	if stateObject != nil &#123;		stateObject.SubBalance(amount)	&#125;&#125;// AddBalance 增加某个账户的余额func (accSt *AccountState) AddBalance(addr common.Address, amount *big.Int) &#123;	stateObject := accSt.getOrsetAccountObject(addr)	if stateObject != nil &#123;		stateObject.AddBalance(amount)	&#125;&#125;//// GetBalance 获取某个账户的余额func (accSt *AccountState) GetBalance(addr common.Address) *big.Int &#123;	stateObject := accSt.getOrsetAccountObject(addr)	if stateObject != nil &#123;		return stateObject.Balance()	&#125;	return new(big.Int).SetInt64(0)&#125;//GetNonce 获取noncefunc (accSt *AccountState) GetNonce(addr common.Address) uint64 &#123;	stateObject := accSt.getAccountObject(addr)	if stateObject != nil &#123;		return stateObject.Nonce()	&#125;	return 0&#125;// SetNonce 设置noncefunc (accSt *AccountState) SetNonce(addr common.Address, nonce uint64) &#123;	stateObject := accSt.getOrsetAccountObject(addr)	if stateObject != nil &#123;		stateObject.SetNonce(nonce)	&#125;&#125;// GetCodeHash 获取代码的hash值func (accSt *AccountState) GetCodeHash(addr common.Address) common.Hash &#123;	stateObject := accSt.getAccountObject(addr)	if stateObject == nil &#123;		return common.Hash&#123;&#125;	&#125;	return common.BytesToHash(stateObject.CodeHash())&#125;//GetCode 获取智能合约的代码func (accSt *AccountState) GetCode(addr common.Address) []byte &#123;	stateObject := accSt.getAccountObject(addr)	if stateObject != nil &#123;		return stateObject.Code()	&#125;	return nil&#125;//SetCode 设置智能合约的codefunc (accSt *AccountState) SetCode(addr common.Address, code []byte) &#123;	stateObject := accSt.getOrsetAccountObject(addr)	if stateObject != nil &#123;		stateObject.SetCode(crypto.Sha256(code), code)	&#125;&#125;// GetCodeSize 获取code的大小func (accSt *AccountState) GetCodeSize(addr common.Address) int &#123;	stateObject := accSt.getAccountObject(addr)	if stateObject == nil &#123;		return 0	&#125;	if stateObject.ByteCode != nil &#123;		return len(stateObject.ByteCode)	&#125;	return 0&#125;// AddRefund 暂时先忽略补偿func (accSt *AccountState) AddRefund(uint64) &#123;	return&#125;//GetRefund ...func (accSt *AccountState) GetRefund() uint64 &#123;	return 0&#125;// GetState 和SetState 是用于保存合约执行时 存储的变量是否发生变化 evm对变量存储的改变消耗的gas是有区别的func (accSt *AccountState) GetState(addr common.Address, key common.Hash) common.Hash &#123;	stateObject := accSt.getAccountObject(addr)	if stateObject != nil &#123;		return stateObject.GetStorageState(key)	&#125;	return common.Hash&#123;&#125;&#125;// SetState 设置变量的状态func (accSt *AccountState) SetState(addr common.Address, key common.Hash, value common.Hash) &#123;	stateObject := accSt.getOrsetAccountObject(addr)	if stateObject != nil &#123;		fmt.Printf(&quot;SetState key: %x value: %s&quot;, key, new(big.Int).SetBytes(value[:]).String())		stateObject.SetStorageState(key, value)	&#125;&#125;// Suicide 暂时禁止自杀func (accSt *AccountState) Suicide(common.Address) bool &#123;	return false&#125;// HasSuicided ...func (accSt *AccountState) HasSuicided(common.Address) bool &#123;	return false&#125;// Exist 检查账户是否存在func (accSt *AccountState) Exist(addr common.Address) bool &#123;	return accSt.getAccountObject(addr) != nil&#125;//Empty 是否是空账户func (accSt *AccountState) Empty(addr common.Address) bool &#123;	so := accSt.getAccountObject(addr)	return so == nil || so.Empty()&#125;// RevertToSnapshot ...func (accSt *AccountState) RevertToSnapshot(int) &#123;&#125;// Snapshot ...func (accSt *AccountState) Snapshot() int &#123;	return 0&#125;// AddLog 添加事件触发日志func (accSt *AccountState) AddLog(log *types.Log) &#123;	fmt.Printf(&quot;log: %v&quot;, log)&#125;// AddPreimage func (accSt *AccountState) AddPreimage(common.Hash, []byte) &#123;&#125;// ForEachStorage  暂时没发现vm调用这个接口func (accSt *AccountState) ForEachStorage(common.Address, func(common.Hash, common.Hash) bool) &#123;&#125;// Commit 进行持久存储 这里我们只将其简单的json话之后保存到本地磁盘中。func (accSt *AccountState) Commit() error &#123;	// 将bincode写入文件	file, err := os.Create(&quot;./account_sate.db&quot;)	if err != nil &#123;		return err	&#125;	err = json.NewEncoder(file).Encode(accSt)	//fmt.Println(&quot;len(binCode): &quot;, len(binCode), &quot; code: &quot;, binCode)	// bufW := bufio.NewWriter(file)	// bufW.Write(binCode)	// // bufW.WriteByte(&#x27;\n&#x27;)	// bufW.Flush()	file.Close()	return err&#125;//TryLoadFromDisk  尝试从磁盘加载AccountStatefunc TryLoadFromDisk() (*AccountState, error) &#123;	file, err := os.Open(&quot;./account_sate.db&quot;)	if err != nil &amp;&amp; os.IsNotExist(err) &#123;		return NewAccountStateDb(), nil	&#125;	if err != nil &#123;		return nil, err	&#125;	// stat, _ := file.Stat()	// // buf := stat.Size()	var accStat AccountState	err = json.NewDecoder(file).Decode(&amp;accStat)	return &amp;accStat, err&#125;


