4. Operational Flags（系统迁移）​​​场景​：核心账户系统数据库迁移​设计模式​：影子流量对比 + 自动回退
import io.getunleash.Unleash;import io.getunleash.UnleashContext;import java.util.Map;import java.util.HashMap;public class AccountService &#123;    private final Unleash unleash;    private final AuditLogger auditLogger;        public AccountService(Unleash unleash, AuditLogger auditLogger) &#123;        this.unleash = unleash;        this.auditLogger = auditLogger;    &#125;    public Balance getBalance(String accountNo) throws BankSystemException &#123;        // 构建Unleash上下文        UnleashContext context = UnleashContext.builder()            .addProperty(&quot;accountType&quot;, getAccountType(accountNo))            .addProperty(&quot;timeWindow&quot;,                 java.time.LocalTime.now().getHour() &lt; 6 ? &quot;low-traffic&quot; : &quot;peak&quot;)            .addProperty(&quot;accountNo&quot;, accountNo) // 用于单账户回退            .build();                boolean useNewDB = unleash.isEnabled(&quot;account_db_migration&quot;, context);                try &#123;            Balance balance = useNewDB ?                 newDbQuery(accountNo) :                 legacyDbQuery(accountNo);                        // 影子流量比对            if (useNewDB) &#123;                Balance legacyBalance = legacyDbQuery(accountNo);                auditLogger.compareResults(&quot;balance_query&quot;, balance, legacyBalance);            &#125;                        return balance;        &#125; catch (Exception ex) &#123;            // 单账户回退（通过Unleash的个性化配置）            Map&lt;String, String&gt; fallbackConfig = new HashMap&lt;&gt;();            fallbackConfig.put(&quot;accountNo&quot;, accountNo);            unleash.more().updateContext(&quot;account_db_migration&quot;,                 &quot;disableForAccount&quot;, fallbackConfig);                        throw new BankSystemException(&quot;DB_OPERATION_FAILED&quot;, ex);        &#125;    &#125;        private Balance newDbQuery(String accountNo) &#123;        // 新数据库查询实现    &#125;        private Balance legacyDbQuery(String accountNo) &#123;        // 旧数据库查询实现    &#125;        private String getAccountType(String accountNo) &#123;        // 获取账户类型逻辑    &#125;&#125;

