5. Permission Flags（权限控制）​​​场景​：企业网银大额审批功能​设计模式​：RBAC + 实时权限同步
import io.getunleash.Unleash;import io.getunleash.UnleashContext;import org.springframework.web.bind.annotation.*;@RestController@RequestMapping(&quot;/api/transfer&quot;)public class TransferApprovalController &#123;    private final Unleash unleash;    private final AuditLogger auditLogger;    public TransferApprovalController(Unleash unleash, AuditLogger auditLogger) &#123;        this.unleash = unleash;        this.auditLogger = auditLogger;    &#125;    @PostMapping(&quot;/approve-large&quot;)    public ResponseEntity&lt;?&gt; approveLargeTransfer(            @RequestBody TransferRequest request,            @RequestHeader(&quot;X-User-Info&quot;) String userInfo) &#123;                // 解析用户信息        User user = parseUserInfo(userInfo);                // 构建Unleash上下文        UnleashContext context = UnleashContext.builder()                .userId(user.getId())                .addProperty(&quot;roles&quot;, String.join(&quot;,&quot;, user.getRoles()))                .addProperty(&quot;amount&quot;, String.valueOf(request.getAmount()))                .addProperty(&quot;branchCode&quot;, user.getBranchCode())                .addProperty(&quot;currency&quot;, request.getCurrency())                .build();        // 检查权限        boolean isApprovalAllowed = unleash.isEnabled(&quot;large_transfer_approval&quot;, context);        if (!isApprovalAllowed) &#123;            auditLogger.logAccessViolation(user.getId(), &quot;large_transfer_approval_denied&quot;, request);            return ResponseEntity.status(HttpStatus.FORBIDDEN)                    .body(new ErrorResponse(&quot;超出审批权限&quot;, &quot;INSUFFICIENT_PRIVILEGES&quot;));        &#125;        // 执行审批逻辑        return processApproval(request, user);    &#125;    private User parseUserInfo(String userInfo) &#123;        // 解析JWT或其它用户信息    &#125;    private ResponseEntity&lt;?&gt; processApproval(TransferRequest request, User user) &#123;        // 审批逻辑实现    &#125;&#125;

